            RT_38 = -1.0E10 * RT_39
         ELSE
            RT_38 =  1.0E10 * RT_39
         ENDIF
      ELSE
         RT_38 = RT_39 / RT_37
      ENDIF
!

! 1020:[hardlimit] Hard Limiter 
!  Hard_Limit
      IF (0.0 .LE. 1.15) THEN
        RT_42 = LIMIT(0.0, 1.15, RT_38)
      ELSE
        RT_42 = RT_38
        IF (STORL(NSTORL) .EQV. .FALSE.) THEN
          CALL EMTDC_WARN(ICALL_NO,1195404760,1,"Lower limit is more tha&
     &n the upper limit, limits not enforced.")
          STORL(NSTORL) = .TRUE.
        ENDIF
      ENDIF
      NSTORL = NSTORL + 1
!

! 1030:[polar_rec] Polar Rectangular coordinate converter 
      RT_41 = RT_42*COS(RT_44)
      RT_43 = RT_42*SIN(RT_44)

