      NRTCI = NRTCI + 1
!

! 1080:[datamerge] Merges data signals into an array 
      RT_32(1) = Varef
      RT_32(2) = Vbref
      RT_32(3) = Vcref

! 1090:[pgb] Output Channel 'Varef'

      DO IVD1_1 = 1, 3
